var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"그러니 이렇게 말씀드리는 것이죠. 향후 국제 관계를 고려해야만 이 협정에 의미가…….","JPN":"ですから、このようにお話ししているのです。今後の国際関係を考えてこそ、この協定の意味が……","ENG":"So here’s what I think. This agreement is meaningful only when considering future international─","TWN":"我的意思就是，必須考慮到之後的國際關係，這個協談才有意義……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"……나다. 무슨 일이지?","JPN":"……私だ。何事だ？","ENG":"…Yes. What’s the problem?","TWN":"……是我，什麼事？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"뭐……? 침식 재난? 3종이라니 확실한가?","JPN":"何……？　侵食災難？　第3種というのは確かなのか？","ENG":"What...? Corruption disaster? Category 3? Are you certain?","TWN":"什麼……？侵蝕災難？確定是3類嗎？"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 감상하시는 중에 죄송하지만 비상 사태입니다.","JPN":"閣下、ご鑑賞の途中申し訳ありませんが、非常事態です。","ENG":"Sir, I’m sorry to bother you, but it’s an emergency.","TWN":"總理，抱歉打擾您欣賞演出，發生緊急事件。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"공작국장 아닌가. 조용히 앉아 있게.","JPN":"工作局長ではないか。静かに座っていたまえ。","ENG":"Ah, Intelligence Chief? Not now, please sit back down.","TWN":"這不是特務部部長嗎？坐。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"아뇨. 중앙대로에 침식체들이 출몰했다는 급보입니다. 어서 몸을 피하셔야 합니다.","JPN":"いいえ。中央大通りに侵食体が出没したという速報です。早く待避なさったほうがよろしいかと。","ENG":"No, please. Corrupted Objects have been spotted on the main street. You have to escape, quickly.","TWN":"不，我們收到消息，侵蝕體出現在中央大道，總理必須儘速避難。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"조용히 앉아 있으라니까. 금방 수그러들 거야.","JPN":"静かに座っていたまえ。すぐ大人しくなるはずだ。","ENG":"I told you to sit down. It’ll be taken care of shortly.","TWN":"我叫你坐下，很快就會沒事的。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하, 반군 세력이라도 여기는 엄연한 외교석상입니다. 대처가 잘못되었다간…….","JPN":"閣下、相手が反乱軍とはいえ、ここは厳然たる外交席上です。対処を間違えたら……","ENG":"Sir, this is a scene of significant diplomatic importance, even for the rebels. If something were to go wrong here─","TWN":"總理，這裡是外交場合，萬一出什麼差錯……"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"금방 수그러들 거라고 하지 않았나? 믿음이 부족하군, 자네.","JPN":"すぐ大人しくなるはずだと言っているではないか？　人を信じないね、君。","ENG":"Did I not just tell you it would be taken care of shortly? You have such little faith.","TWN":"我不是說很快就會沒事嗎？你的疑心病很重呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"안 그렇습니까, 학회장님?","JPN":"そう思いませんか、学会長？","ENG":"Don’t you think, President?","TWN":"學會長，您說是不是？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L22_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"저희는 괜찮아요. 외부에 알려지지 않은 현상이니 당황하실 수밖에요.","JPN":"我々は大丈夫です。外には知らされていない現象ですので、戸惑うのも当たり前です。","ENG":"We are fine. It is a rather unknown phenomenon for others, so you can’t help but be flustered.","TWN":"我們是無所謂，畢竟沒有對外公開，他們會驚慌也是人之常情。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"걱정하지 마세요. 이건 전부 거쳐 가는 과정에 불과하답니다.","JPN":"心配いりませんよ。これは全部過程に過ぎません。","ENG":"Don’t worry. It’s just a part of the process.","TWN":"放心吧，這些都只是必經的過程而已。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"거쳐 가는 과정이라니…… 이것들이 각하를 등에 업었다고 무슨 망발을……!","JPN":"過程だと……閣下を後ろ盾にしているからとはいえ、ふざけたことを……！","ENG":"Part of the process... What do you mean, what are you─!","TWN":"必經的過程……仗著有總理給你們靠就可以亂說話嗎……！"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"수행인으로서 이런 말씀을 드리기는 저어되지만, 그건 전후 관계가 잘못되었습니다.","JPN":"随行員として、このようなことを申し上げるのは慎みたいのですが、それは前後関係が間違っております。","ENG":"As a mere companion, I am hesitant to say this, but you've misread the context.","TWN":"身為隨行的人，說這種話恐怕不恰當，但您的說法似乎不太正確。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"총리님이 지금 자리에 오르신 건 학회의 조력 덕분이니 말이오.","JPN":"総理が今の地位になったのは学会の助力があってこそですから。","ENG":"The Prime Minister is in the office thanks to the Society’s assistance.","TWN":"總理之所以能坐上總理的位置，完全是拜學會所賜。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"조력……?","JPN":"助力……？","ENG":"Assistance...?","TWN":"拜學會所賜……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"학회장님, 계측된 침식파가 방향성을 갖기 시작했습니다.","JPN":"学会長、計測された侵食波が方向性を持ち始めました。","ENG":"Ms. President, the measured Corruption ray has begun to take a direction.","TWN":"學會長，測量到的侵蝕波開始具有方向性，"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이제 곧 출몰할 모양이군요. 가서 감상하는 것을 허락해 주시겠습니까?","JPN":"もうすぐ出没するようです。現場に行って鑑賞することをお許しくださいますか？","ENG":"It should begin appearing shortly. With your permission, shall I go and appreciate it for myself?","TWN":"似乎就快要現身，可否容我前往觀賞？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"그래요. 좀처럼 보기 힘든 광경이니까요. 교수님의 지식에 보탬이 될 수 있겠네요.","JPN":"いいですよ。なかなか見ることができない光景ですからね。教授の知識に役立つかもしれません。","ENG":"Very well. It is certainly a rare sight. It could be helpful for your studies.","TWN":"去吧，這麼難得一見的景象，相信對教授的知識也會有幫助的。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"PROFESSOR_NPC_NULL_NULL","text":{"KOREA":"이번에도 제 마음을 헤아려 주셨군요. 감사합니다, 학회장님.","JPN":"今回も私の心を察してくださったのですね。ありがとうございます、学会長。","ENG":"You know me so well, President. Thank you.","TWN":"謝謝學會長，總是如此善解人意。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L35_1","type":"dialog","speaker":"EDEL_ESPR_NULL_NULL","text":{"KOREA":"아니에요. 교수님 같은 분들이 지식을 쌓으셔야 레지나님도 편안히 지내시죠.","JPN":"いいえ。教授のような方々が知識を深めてこそ、レジーナ様も楽に過ごせるでしょう。","ENG":"It is the least we could do. You should keep up with your own studies so that Miss Regina can live in ease.","TWN":"別客氣，教授要多累積知識，蕾佳娜才能輕鬆一點的嘛。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PROFESSOR_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EDEL_ESPR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L37_1","type":"dialog","speaker":"SIR_GRONIA_NULL_NULL","text":{"KOREA":"각하……. 저들이 한 말, 설마 진실입니까……?","JPN":"閣下……あの者たちの言うこと、まさか本当ですか……？","ENG":"Sir... What they said, it can’t be true...?","TWN":"總理……他們說的，是真的嗎……？"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"……분수에 넘치는 것을 알려고 하지 말게나.","JPN":"……身分をわきまえたまえ。","ENG":"...Do not overstep yourself.","TWN":"……不干你的事就別問。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"자리가 비었으니 앉지.","JPN":"席が空いている、座ったらどうだ。","ENG":"Let’s go sit down.","TWN":"現在位置空著，坐吧。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SIR_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"PRIME_NPC_NULL_NULL","text":{"KOREA":"아직 우리 아리따운 학회원께서 혼신을 다해 연주 중이시잖나.","JPN":"まだ我々の美しい学会員が渾身の演奏をしているではないか。","ENG":"I see our dazzling Society member is still playing with all her might.","TWN":"我們美麗的學會員正使出混身解數在演奏呢。"},"stage":{"bg":"GRONIA_HALL","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BASS_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};